1	/**
2	 * The Laboratory's phase orchestrator engines.
3	 *
4	 * The post-and-collect-default rig template enumerates five phases as
5	 * a backbone (setup → scenario → probes → archive → teardown), one
6	 * engine per phase. Each phase engine is a clockwork orchestrator: it
7	 * reads `writ.ext.laboratory.config`, computes the per-phase graft,
8	 * and returns immediately with `{ status: 'completed', graft, ...}`.
9	 * The grafted engines do the real work; phase orchestrators are
10	 * organizational.
11	 *
12	 * Phase orchestrators do not isolate data — all grafted engines
13	 * share a single namespace, so cross-phase upstream refs work
14	 * naturally. Engine ids follow stable naming conventions
15	 * (`fixture-<id>-setup`, `scenario`, `probe-<id>`, `archive`,
16	 * `fixture-<id>-teardown`); each phase derives the ids it needs
17	 * from the trial config without going through prior phases' yields.
18	 *
19	 * Why staged phases instead of one god orchestrator:
20	 *
21	 *   - Template documents the trial flow as the user-facing shape
22	 *     (the template is no longer a one-engine no-op).
23	 *   - Per-phase failure visibility: oculus shows
24	 *     `lab.probes-phase` failed, not "the orchestrator failed
25	 *     somewhere".
26	 *   - Each phase has cohesive logic (DAG sort, parallel scatter,
27	 *     reverse-sequential chain) — splitting them avoids one big
28	 *     function with phase-mode flags.
29	 *   - Sets up the extension point: a future plugin contributing a
30	 *     `lab.warmup-phase` slots into a custom template alongside
31	 *     existing phases without forking a god engine.
32	 *
33	 * graftTail is set only on `lab.teardown-phase` (the rig's true end
34	 * for completion gating). Intermediate phase orchestrators omit
35	 * graftTail so each next phase fires immediately when the prior
36	 * orchestrator returns — real work-engines wait via their explicit
37	 * upstream refs, not graftTail propagation.
38	 */
39	
40	import type { EngineDesign, EngineRunResult } from '@shardworks/fabricator-apparatus';
41	import type { WritDoc } from '@shardworks/clerk-apparatus';
42	import type { RigTemplateEngine, SpiderEngineRunResult } from '@shardworks/spider-apparatus';
43	import type { LaboratoryTrialConfig, TrialFixtureDecl } from '../types.ts';
44	
45	// ── Shared helpers ─────────────────────────────────────────────────
46	
47	/**
48	 * Stable engine-id naming conventions. Every phase derives the ids
49	 * it needs from the trial config using these helpers — no
50	 * cross-phase data flow is required for naming.
51	 */
52	export const SETUP_ID = (fixtureId: string): string => `fixture-${fixtureId}-setup`;
53	export const TEARDOWN_ID = (fixtureId: string): string => `fixture-${fixtureId}-teardown`;
54	export const SCENARIO_ID = 'scenario';
55	export const PROBE_ID = (probeId: string): string => `probe-${probeId}`;
56	export const ARCHIVE_ID = 'archive';
57	
58	/**
59	 * Convention: derive a fixture's teardown engine id from its setup
60	 * engine id when no explicit override is provided. Replaces a
61	 * trailing `-setup` with `-teardown`. If the setup id does not end
62	 * in `-setup`, appends `-teardown`.
63	 */
64	export function deriveTeardownEngineId(fixture: TrialFixtureDecl): string {
65	  if (fixture.teardownEngineId !== undefined) return fixture.teardownEngineId;
66	  if (fixture.engineId.endsWith('-setup')) {
67	    return fixture.engineId.replace(/-setup$/, '-teardown');
68	  }
69	  return `${fixture.engineId}-teardown`;
70	}
71	
72	/**
73	 * Topologically sort fixtures by dependsOn. Every fixture appears
74	 * after all of its dependencies. Stable: among fixtures whose
75	 * dependencies are all already placed, declaration order is
76	 * preserved.
77	 *
78	 * Throws on cycles, unknown dependsOn references, or duplicate ids.
79	 */
80	export function topoSortFixtures(fixtures: TrialFixtureDecl[]): TrialFixtureDecl[] {
81	  const byId = new Map<string, TrialFixtureDecl>();
82	  for (const fixture of fixtures) {
83	    if (byId.has(fixture.id)) {
84	      throw new Error(`[lab] duplicate fixture id: "${fixture.id}"`);
85	    }
86	    byId.set(fixture.id, fixture);
87	  }
88	
89	  for (const fixture of fixtures) {
90	    for (const dep of fixture.dependsOn ?? []) {
91	      if (!byId.has(dep)) {
92	        throw new Error(
93	          `[lab] fixture "${fixture.id}" dependsOn unknown fixture "${dep}"`,
94	        );
95	      }
96	    }
97	  }
98	
99	  const result: TrialFixtureDecl[] = [];
100	  const placed = new Set<string>();
101	  const remaining = [...fixtures];
102	
103	  while (remaining.length > 0) {
104	    const before = remaining.length;
105	    for (let i = 0; i < remaining.length; i += 1) {
106	      const fixture = remaining[i]!;
107	      const deps = fixture.dependsOn ?? [];
108	      if (deps.every((d) => placed.has(d))) {
109	        result.push(fixture);
110	        placed.add(fixture.id);
111	        remaining.splice(i, 1);
112	        i -= 1;
113	      }
114	    }
115	    if (remaining.length === before) {
116	      const ids = remaining.map((f) => f.id).join(', ');
117	      throw new Error(`[lab] fixture dependsOn cycle among: ${ids}`);
118	    }
119	  }
120	
121	  return result;
122	}
123	
124	/**
125	 * Read and validate the trial config from a writ. All phase
126	 * orchestrators share this entry path — fail-loud on missing
127	 * config so the manifest CLI's validation contract is the only
128	 * gate.
129	 */
130	function readTrialConfig(givens: Record<string, unknown>, phaseEngineId: string): {
131	  writ: WritDoc;
132	  config: LaboratoryTrialConfig;
133	} {
134	  const writ = givens.writ as WritDoc | undefined;
135	  if (!writ) {
136	    throw new Error(
137	      `[${phaseEngineId}] missing required given "writ" — the rig template must pass \${writ}.`,
138	    );
139	  }
140	  const config = (writ.ext as { laboratory?: { config?: LaboratoryTrialConfig } } | undefined)
141	    ?.laboratory?.config;
142	  if (!config) {
143	    throw new Error(
144	      `[${phaseEngineId}] trial writ ${writ.id} missing ext.laboratory.config — manifest CLI should reject this at post time.`,
145	    );
146	  }
147	  return { writ, config };
148	}
149	
150	// ── Trial-context injection ────────────────────────────────────────
151	
152	/**
153	 * Trial-level context auto-injected into every grafted work engine's
154	 * givens under the `_trial` key. Engines read this for trial-aware
155	 * defaulting (e.g. codex-setup deriving its codexName from slug+writId
156	 * when the manifest doesn't supply one explicitly).
157	 *
158	 * The underscore prefix marks the key as framework-injected; manifest
159	 * authors should not set `_trial` themselves. Author-supplied `_trial`
160	 * (if any) is overwritten — the orchestrator's view of trial context
161	 * is authoritative.
162	 */
163	export interface InjectedTrialContext {
164	  /** The trial slug. */
165	  slug: string;
166	  /** The trial writ id (the canonical id for this trial). */
167	  writId: string;
168	  /** The fixture's id within the trial — only present on fixture engines. */
169	  fixtureId?: string;
170	}
171	
172	function withTrialContext(
173	  givens: Record<string, unknown>,
174	  trial: InjectedTrialContext,
175	): Record<string, unknown> {
176	  return { ...givens, _trial: trial };
177	}
178	
179	// ── Per-phase graft builders (pure; tested directly) ───────────────
180	
181	/**
182	 * Build the setup phase's graft: one engine per fixture, in topo
183	 * order. A fixture's setup engine upstreams its dependsOn fixtures'
184	 * setup engines (or the head — `headEngineId` — when it has no
185	 * deps).
186	 *
187	 * Each fixture engine's givens get an injected `_trial` block carrying
188	 * the trial slug, writ id, and fixture id (see InjectedTrialContext).
189	 */
190	export function buildSetupGraft(
191	  config: LaboratoryTrialConfig,
192	  headEngineId: string,
193	  writId: string,
194	): { graft: RigTemplateEngine[]; ordered: TrialFixtureDecl[] } {
195	  const ordered = topoSortFixtures(config.fixtures);
196	  const graft: RigTemplateEngine[] = [];
197	  for (const fixture of ordered) {
198	    const deps = fixture.dependsOn ?? [];
199	    const upstream = deps.length > 0 ? deps.map(SETUP_ID) : [headEngineId];
200	    graft.push({
201	      id: SETUP_ID(fixture.id),
202	      designId: fixture.engineId,
203	      upstream,
204	      givens: withTrialContext(fixture.givens, {
205	        slug: config.slug,
206	        writId,
207	        fixtureId: fixture.id,
208	      }),
209	    });
210	  }
211	  return { graft, ordered };
212	}
213	
214	/**
215	 * Build the scenario phase's graft: one engine for the scenario.
216	 * Upstreams every fixture's setup engine, so it waits for the full
217	 * setup wave to complete. When there are no fixtures, upstreams
218	 * the head (the scenario phase orchestrator's own id).
219	 */
220	export function buildScenarioGraft(
221	  config: LaboratoryTrialConfig,
222	  headEngineId: string,
223	  writId: string,
224	): RigTemplateEngine[] {
225	  const upstream =
226	    config.fixtures.length > 0
227	      ? topoSortFixtures(config.fixtures).map((f) => SETUP_ID(f.id))
228	      : [headEngineId];
229	  return [
230	    {
231	      id: SCENARIO_ID,
232	      designId: config.scenario.engineId,
233	      upstream,
234	      givens: withTrialContext(config.scenario.givens, {
235	        slug: config.slug,
236	        writId,
237	      }),
238	    },
239	  ];
240	}
241	
242	/**
243	 * Build the probes phase's graft: one engine per probe. Each probe
244	 * upstreams the scenario engine; probes themselves run in parallel.
245	 */
246	export function buildProbesGraft(
247	  config: LaboratoryTrialConfig,
248	  writId: string,
249	): RigTemplateEngine[] {
250	  return config.probes.map((probe) => ({
251	    id: PROBE_ID(probe.id),
252	    designId: probe.engineId,
253	    upstream: [SCENARIO_ID],
254	    givens: withTrialContext(probe.givens, {
255	      slug: config.slug,
256	      writId,
257	    }),
258	  }));
259	}
260	
261	/**
262	 * Build the archive phase's graft: one archive engine. Upstreams
263	 * every probe engine; or the scenario engine when there are no
264	 * probes.
265	 */
266	export function buildArchiveGraft(
267	  config: LaboratoryTrialConfig,
268	  writId: string,
269	): RigTemplateEngine[] {
270	  const upstream =
271	    config.probes.length > 0
272	      ? config.probes.map((p) => PROBE_ID(p.id))
273	      : [SCENARIO_ID];
274	  return [
275	    {
276	      id: ARCHIVE_ID,
277	      designId: config.archive.engineId,
278	      upstream,
279	      givens: withTrialContext(config.archive.givens, {
280	        slug: config.slug,
281	        writId,
282	      }),
283	    },
284	  ];
285	}
286	
287	/**
288	 * Build the teardown phase's graft: one engine per fixture, REVERSE
289	 * topo order, sequential chain rooted at archive. Sequential (not
290	 * parallel) so a teardown failure stops the chain rather than
291	 * shredding sibling teardowns concurrently.
292	 *
293	 * Returns the graft and the tail engine id (the rig's true end —
294	 * teardown phase sets graftTail to this for completion gating).
295	 */
296	export function buildTeardownGraft(
297	  config: LaboratoryTrialConfig,
298	  writId: string,
299	): { graft: RigTemplateEngine[]; tail: string } {
300	  const ordered = topoSortFixtures(config.fixtures);
301	  const graft: RigTemplateEngine[] = [];
302	  let prevTail: string = ARCHIVE_ID;
303	  for (let i = ordered.length - 1; i >= 0; i -= 1) {
304	    const fixture = ordered[i]!;
305	    const id = TEARDOWN_ID(fixture.id);
306	    graft.push({
307	      id,
308	      designId: deriveTeardownEngineId(fixture),
309	      upstream: [prevTail],
310	      givens: withTrialContext(fixture.givens, {
311	        slug: config.slug,
312	        writId,
313	        fixtureId: fixture.id,
314	      }),
315	    });
316	    prevTail = id;
317	  }
318	  return { graft, tail: prevTail };
319	}
320	
321	// ── Phase orchestrator engines ─────────────────────────────────────
322	
323	const setupPhaseEngine: EngineDesign = {
324	  id: 'lab.setup-phase',
325	  async run(givens, context): Promise<EngineRunResult> {
326	    const { writ, config } = readTrialConfig(givens, 'lab.setup-phase');
327	    const { graft, ordered } = buildSetupGraft(config, context.engineId, writ.id);
328	    const result: SpiderEngineRunResult = {
329	      status: 'completed',
330	      yields: {
331	        fixtureCount: ordered.length,
332	        fixtureIds: ordered.map((f) => f.id),
333	      },
334	      graft,
335	      // graftTail intentionally unset: the scenario engine has
336	      //   explicit upstream refs into each fixture-setup, so the
337	      //   scenario phase can fire immediately upon this engine's
338	      //   return without waiting for fixtures to complete first.
339	    };
340	    return result as EngineRunResult;
341	  },
342	};
343	
344	const scenarioPhaseEngine: EngineDesign = {
345	  id: 'lab.scenario-phase',
346	  async run(givens, context): Promise<EngineRunResult> {
347	    const { writ, config } = readTrialConfig(givens, 'lab.scenario-phase');
348	    const graft = buildScenarioGraft(config, context.engineId, writ.id);
349	    const result: SpiderEngineRunResult = {
350	      status: 'completed',
351	      yields: { scenarioEngine: config.scenario.engineId },
352	      graft,
353	    };
354	    return result as EngineRunResult;
355	  },
356	};
357	
358	const probesPhaseEngine: EngineDesign = {
359	  id: 'lab.probes-phase',
360	  async run(givens): Promise<EngineRunResult> {
361	    const { writ, config } = readTrialConfig(givens, 'lab.probes-phase');
362	    const graft = buildProbesGraft(config, writ.id);
363	    const result: SpiderEngineRunResult = {
364	      status: 'completed',
365	      yields: {
366	        probeCount: config.probes.length,
367	        probeIds: config.probes.map((p) => p.id),
368	      },
369	      graft,
370	    };
371	    return result as EngineRunResult;
372	  },
373	};
374	
375	const archivePhaseEngine: EngineDesign = {
376	  id: 'lab.archive-phase',
377	  async run(givens): Promise<EngineRunResult> {
378	    const { writ, config } = readTrialConfig(givens, 'lab.archive-phase');
379	    const graft = buildArchiveGraft(config, writ.id);
380	    const result: SpiderEngineRunResult = {
381	      status: 'completed',
382	      yields: { archiveEngine: config.archive.engineId },
383	      graft,
384	    };
385	    return result as EngineRunResult;
386	  },
387	};
388	
389	const teardownPhaseEngine: EngineDesign = {
390	  id: 'lab.teardown-phase',
391	  async run(givens): Promise<EngineRunResult> {
392	    const { writ, config } = readTrialConfig(givens, 'lab.teardown-phase');
393	    const { graft, tail } = buildTeardownGraft(config, writ.id);
394	    const result: SpiderEngineRunResult = {
395	      status: 'completed',
396	      yields: { teardownCount: config.fixtures.length },
397	      graft,
398	      // graftTail set: this is the rig's true end. Spider waits
399	      //   for `tail` to complete before considering the rig done.
400	      //   When there are no fixtures, tail equals ARCHIVE_ID — the
401	      //   archive engine is the last real work in that case.
402	      graftTail: tail,
403	    };
404	    return result as EngineRunResult;
405	  },
406	};
407	
408	export const phaseEngines = {
409	  'lab.setup-phase': setupPhaseEngine,
410	  'lab.scenario-phase': scenarioPhaseEngine,
411	  'lab.probes-phase': probesPhaseEngine,
412	  'lab.archive-phase': archivePhaseEngine,
413	  'lab.teardown-phase': teardownPhaseEngine,
414	} as const;
415

