1	/**
2	 * lab.guild-setup / lab.guild-teardown — fixture engines for a per-trial
3	 * test guild.
4	 *
5	 * MOTIVATION
6	 * ──────────
7	 * A trial wants a fresh, disposable guild instance to commission work
8	 * into. The guild needs:
9	 *   - The right plugins installed (varies per trial: every plugin the
10	 *     test workload exercises must be there).
11	 *   - The codexes from upstream fixtures registered (so the test guild
12	 *     knows about them).
13	 *   - Optional `guild.json` overlay (e.g. configuring patron role for
14	 *     astrolabe).
15	 *   - Optional file copies (e.g. a custom prompt template for animator).
16	 *
17	 * SETUP FLOW
18	 * ──────────
19	 * 1. Validate givens; resolve guildName + guildPath.
20	 * 2. Refuse if the target dir already exists (idempotency / safety).
21	 * 3. `nsg init <guildPath>`.
22	 * 4. For each plugin pin: `nsg --guild-root <guildPath> plugin install
23	 *    <name>@<version>`.
24	 * 5. Discover codexes from `context.upstream`: any upstream yields with
25	 *    `codexName` + `remoteUrl` (the codex-fixture's yields shape) get
26	 *    registered via `nsg --guild-root <guildPath> codex add`. Walks all
27	 *    upstream entries — no manifest-level dependsOn declaration of
28	 *    "this is the codex" needed.
29	 * 6. Deep-merge `givens.config` into `<guildPath>/guild.json`.
30	 * 7. Copy each `givens.files[]` entry from `sourcePath` (absolute only
31	 *    in v1) to `<guildPath>/<guildPath>` (per-entry guildPath).
32	 * 8. Yield guildPath, pluginsResolved, codexesAdded, filesCopied.
33	 *
34	 * Failure handling: any error mid-setup triggers best-effort rollback
35	 * (rm -rf the guild dir) and re-throws.
36	 *
37	 * TEARDOWN FLOW
38	 * ─────────────
39	 * 1. Validate givens; resolve guildPath.
40	 * 2. Archive-safety check (same as codex-teardown).
41	 * 3. `rm -rf <guildPath>`.
42	 * 4. Yield `{ removed: true, guildPath }`.
43	 *
44	 * GIVENS (setup AND teardown — fixture givens are shared)
45	 * ───────────────────────────────────────────────────────
46	 *   guildName : string?  — Optional. The test guild's identity name.
47	 *                          Defaults to `<slug>-<writId-tail>` from the
48	 *                          framework-injected `_trial` context (matches
49	 *                          the codex-fixture's default-naming convention).
50	 *   guildPath : string?  — Optional. Absolute path for the test guild dir.
51	 *                          Defaults to
52	 *                          `<labHostGuild>/.nexus/laboratory/guilds/<guildName>/`.
53	 *   plugins   : Array<{name, version}>?  — Optional. Plugin pins to install.
54	 *                          Each entry is shelled out as
55	 *                          `nsg plugin install <name>@<version>`. Version
56	 *                          accepts npm semver, dist-tags, git URLs with
57	 *                          `#<sha>`, and local paths — passed through to
58	 *                          npm unchanged.
59	 *   config    : object?   — Optional. Deep-merged into the guild's
60	 *                          `guild.json` after init.
61	 *   files     : Array<{sourcePath, guildPath}>?  — Optional. File copies.
62	 *                          sourcePath must be absolute in v1 (throws on
63	 *                          relative). guildPath is relative to the guild
64	 *                          root.
65	 *
66	 * YIELDS (setup)
67	 * ──────────────
68	 *   {
69	 *     guildName: string,
70	 *     guildPath: string,
71	 *     pluginsResolved: Array<{ name: string; version: string }>,
72	 *     codexesAdded: Array<{ codexName: string; remoteUrl: string }>,
73	 *     filesCopied: Array<{ sourcePath: string; guildPath: string }>,
74	 *   }
75	 *
76	 * YIELDS (teardown)
77	 * ─────────────────
78	 *   { removed: true, guildName: string, guildPath: string }
79	 */
80	
81	import { execFile as execFileCb } from 'node:child_process';
82	import { promisify } from 'node:util';
83	import { existsSync } from 'node:fs';
84	import { copyFile, mkdir, readFile, rm, writeFile } from 'node:fs/promises';
85	import path from 'node:path';
86	import { guild } from '@shardworks/nexus-core';
87	import type {
88	  EngineDesign,
89	  EngineRunContext,
90	  EngineRunResult,
91	} from '@shardworks/fabricator-apparatus';
92	import type { InjectedTrialContext } from './phases.ts';
93	
94	const execFile = promisify(execFileCb);
95	
96	// ── Givens validation ────────────────────────────────────────────────
97	
98	export interface PluginPin {
99	  name: string;
100	  version: string;
101	}
102	
103	export interface FileCopy {
104	  sourcePath: string;
105	  guildPath: string;
106	}
107	
108	interface ResolvedGuildFixtureGivens {
109	  guildName: string;
110	  guildPath: string;
111	  plugins: PluginPin[];
112	  config: Record<string, unknown>;
113	  files: FileCopy[];
114	}
115	
116	/**
117	 * Guild-name rules — used as the test guild's `name` field and as the
118	 * default dir basename. Conservative: kebab-case, 1–60 chars.
119	 */
120	const GUILD_NAME_PATTERN = /^[a-z][a-z0-9-]{0,59}$/;
121	
122	/**
123	 * Compute the default guild name from the framework-injected `_trial`
124	 * context: `<slug>-<writIdTail>`. Returns null when `_trial` is missing
125	 * or malformed.
126	 */
127	function defaultGuildName(givens: Record<string, unknown>): string | null {
128	  const trial = givens._trial as InjectedTrialContext | undefined;
129	  if (!trial || typeof trial.slug !== 'string' || typeof trial.writId !== 'string') {
130	    return null;
131	  }
132	  const tail = (trial.writId.split('-').pop() ?? trial.writId).slice(0, 8);
133	  return `${trial.slug}-${tail}`;
134	}
135	
136	/**
137	 * Resolve the default guild path inside the lab-host guild's filesystem.
138	 * Mirrors the codex-fixture's `.nexus/laboratory/codexes/<name>.git`
139	 * placement: lab-host-internal, namespaced under `.nexus/laboratory/`.
140	 */
141	export function defaultGuildPath(labHostGuildHome: string, guildName: string): string {
142	  return path.join(labHostGuildHome, '.nexus', 'laboratory', 'guilds', guildName);
143	}
144	
145	function validateGivens(
146	  rawGivens: Record<string, unknown>,
147	  designId: string,
148	): ResolvedGuildFixtureGivens {
149	  // Resolve guildName.
150	  let guildName = rawGivens.guildName;
151	  if (guildName === undefined || guildName === null) {
152	    const fallback = defaultGuildName(rawGivens);
153	    if (fallback === null) {
154	      throw new Error(
155	        `[${designId}] givens.guildName is missing and no _trial context was injected. ` +
156	          `Either author guildName explicitly, or ensure the engine runs under the ` +
157	          `Laboratory phase orchestrators.`,
158	      );
159	    }
160	    guildName = fallback;
161	  }
162	  if (typeof guildName !== 'string' || !GUILD_NAME_PATTERN.test(guildName)) {
163	    throw new Error(
164	      `[${designId}] guildName must be kebab-case (start with a letter; ` +
165	        `alphanumeric and hyphens; ≤60 chars); got "${String(guildName)}".`,
166	    );
167	  }
168	
169	  // Resolve guildPath.
170	  let guildPath = rawGivens.guildPath;
171	  if (guildPath === undefined || guildPath === null) {
172	    guildPath = defaultGuildPath(guild().home, guildName);
173	  }
174	  if (typeof guildPath !== 'string' || !path.isAbsolute(guildPath)) {
175	    throw new Error(
176	      `[${designId}] guildPath must be an absolute path; got "${String(guildPath)}".`,
177	    );
178	  }
179	
180	  // Plugins.
181	  const rawPlugins = rawGivens.plugins ?? [];
182	  if (!Array.isArray(rawPlugins)) {
183	    throw new Error(
184	      `[${designId}] givens.plugins must be an array of {name, version}; got ` +
185	        `${typeof rawPlugins}.`,
186	    );
187	  }
188	  const plugins: PluginPin[] = [];
189	  for (let i = 0; i < rawPlugins.length; i += 1) {
190	    const p = rawPlugins[i] as Record<string, unknown> | undefined;
191	    if (!p || typeof p.name !== 'string' || typeof p.version !== 'string') {
192	      throw new Error(
193	        `[${designId}] givens.plugins[${i}] must be {name: string, version: string}; ` +
194	          `got ${JSON.stringify(p)}.`,
195	      );
196	    }
197	    plugins.push({ name: p.name, version: p.version });
198	  }
199	
200	  // Config.
201	  const rawConfig = rawGivens.config ?? {};
202	  if (!isPlainObject(rawConfig)) {
203	    throw new Error(
204	      `[${designId}] givens.config must be a plain object; got ${typeof rawConfig}.`,
205	    );
206	  }
207	
208	  // Files.
209	  const rawFiles = rawGivens.files ?? [];
210	  if (!Array.isArray(rawFiles)) {
211	    throw new Error(
212	      `[${designId}] givens.files must be an array of {sourcePath, guildPath}; got ` +
213	        `${typeof rawFiles}.`,
214	    );
215	  }
216	  const files: FileCopy[] = [];
217	  for (let i = 0; i < rawFiles.length; i += 1) {
218	    const f = rawFiles[i] as Record<string, unknown> | undefined;
219	    if (!f || typeof f.sourcePath !== 'string' || typeof f.guildPath !== 'string') {
220	      throw new Error(
221	        `[${designId}] givens.files[${i}] must be {sourcePath: string, guildPath: string}; ` +
222	          `got ${JSON.stringify(f)}.`,
223	      );
224	    }
225	    if (!path.isAbsolute(f.sourcePath)) {
226	      throw new Error(
227	        `[${designId}] givens.files[${i}].sourcePath must be absolute in v1 ` +
228	          `(manifest-relative resolution is future work); got "${f.sourcePath}".`,
229	      );
230	    }
231	    if (path.isAbsolute(f.guildPath)) {
232	      throw new Error(
233	        `[${designId}] givens.files[${i}].guildPath must be relative to the guild root; ` +
234	          `got absolute "${f.guildPath}".`,
235	      );
236	    }
237	    files.push({ sourcePath: f.sourcePath, guildPath: f.guildPath });
238	  }
239	
240	  return { guildName, guildPath, plugins, config: rawConfig, files };
241	}
242	
243	// ── Helpers ──────────────────────────────────────────────────────────
244	
245	function isPlainObject(v: unknown): v is Record<string, unknown> {
246	  return (
247	    typeof v === 'object' &&
248	    v !== null &&
249	    !Array.isArray(v) &&
250	    Object.getPrototypeOf(v) === Object.prototype
251	  );
252	}
253	
254	/**
255	 * Recursive deep-merge — source overrides target. Plain objects are
256	 * merged structurally; arrays and scalars from source replace target
257	 * outright. Non-mutating.
258	 */
259	export function deepMerge(
260	  target: Record<string, unknown>,
261	  source: Record<string, unknown>,
262	): Record<string, unknown> {
263	  const result: Record<string, unknown> = { ...target };
264	  for (const [k, v] of Object.entries(source)) {
265	    if (isPlainObject(v) && isPlainObject(result[k])) {
266	      result[k] = deepMerge(result[k] as Record<string, unknown>, v);
267	    } else {
268	      result[k] = v;
269	    }
270	  }
271	  return result;
272	}
273	
274	/**
275	 * Discover codexes from upstream yields — any object that has both
276	 * `codexName: string` and `remoteUrl: string` is treated as a codex
277	 * to register in the test guild. Matches the codex-fixture's yield
278	 * shape exactly.
279	 */
280	export interface DiscoveredCodex {
281	  codexName: string;
282	  remoteUrl: string;
283	}
284	
285	export function discoverCodexes(
286	  upstream: Record<string, unknown>,
287	): DiscoveredCodex[] {
288	  const result: DiscoveredCodex[] = [];
289	  for (const value of Object.values(upstream)) {
290	    if (
291	      typeof value === 'object' &&
292	      value !== null &&
293	      !Array.isArray(value)
294	    ) {
295	      const obj = value as Record<string, unknown>;
296	      if (typeof obj.codexName === 'string' && typeof obj.remoteUrl === 'string') {
297	        result.push({ codexName: obj.codexName, remoteUrl: obj.remoteUrl });
298	      }
299	    }
300	  }
301	  return result;
302	}
303	
304	/**
305	 * Run a command via execFile — no shell, predictable arg quoting.
306	 * Throws with stderr on non-zero exit.
307	 */
308	async function exec(
309	  cmd: string,
310	  args: string[],
311	  cwd?: string,
312	): Promise<{ stdout: string; stderr: string }> {
313	  try {
314	    const { stdout, stderr } = await execFile(cmd, args, {
315	      cwd,
316	      maxBuffer: 50 * 1024 * 1024,
317	    });
318	    return { stdout: stdout.trim(), stderr: stderr.trim() };
319	  } catch (err: unknown) {
320	    const e = err as { stderr?: string; message?: string };
321	    throw new Error(
322	      `${cmd} ${args.join(' ')} failed: ${e.stderr || e.message || 'unknown error'}`,
323	    );
324	  }
325	}
326	
327	// ── Setup engine ─────────────────────────────────────────────────────
328	
329	export const guildSetupEngine: EngineDesign = {
330	  id: 'lab.guild-setup',
331	  async run(rawGivens, context: EngineRunContext): Promise<EngineRunResult> {
332	    const givens = validateGivens(rawGivens, 'lab.guild-setup');
333	    const { guildName, guildPath, plugins, config, files } = givens;
334	
335	    if (existsSync(guildPath)) {
336	      throw new Error(
337	        `[lab.guild-setup] target dir already exists at ${guildPath}; refusing to clobber. ` +
338	          `Guild name "${guildName}" likely collides with an active trial — pick a unique name.`,
339	      );
340	    }
341	
342	    let initialized = false;
343	
344	    try {
345	      // 1. nsg init <guildPath> — creates dir, guild.json, package.json,
346	      //    .gitignore. Refuses if dir is non-empty (idempotency belt-and-
347	      //    suspenders alongside our own existsSync check above).
348	      await mkdir(path.dirname(guildPath), { recursive: true });
349	      await exec('nsg', ['init', guildPath, '--name', guildName]);
350	      initialized = true;
351	
352	      // 2. Plugin install. Sequential, not parallel — npm install in the
353	      //    same dir doesn't tolerate concurrency, and order matters when
354	      //    plugins declare peer/optional deps.
355	      const pluginsResolved: PluginPin[] = [];
356	      for (const pin of plugins) {
357	        const spec = `${pin.name}@${pin.version}`;
358	        await exec('nsg', ['--guild-root', guildPath, 'plugin', 'install', spec]);
359	        pluginsResolved.push(pin);
360	      }
361	
362	      // 3. Codex registration from upstream.
363	      const codexesAdded: DiscoveredCodex[] = [];
364	      const discovered = discoverCodexes(context.upstream);
365	      for (const codex of discovered) {
366	        await exec('nsg', [
367	          '--guild-root',
368	          guildPath,
369	          'codex',
370	          'add',
371	          '--name',
372	          codex.codexName,
373	          '--remote-url',
374	          codex.remoteUrl,
375	        ]);
376	        codexesAdded.push(codex);
377	      }
378	
379	      // 4. Deep-merge config into guild.json.
380	      if (Object.keys(config).length > 0) {
381	        const guildJsonPath = path.join(guildPath, 'guild.json');
382	        const existing = JSON.parse(await readFile(guildJsonPath, 'utf8')) as Record<
383	          string,
384	          unknown
385	        >;
386	        const merged = deepMerge(existing, config);
387	        await writeFile(guildJsonPath, JSON.stringify(merged, null, 2) + '\n');
388	      }
389	
390	      // 5. File copies.
391	      const filesCopied: FileCopy[] = [];
392	      for (const file of files) {
393	        const dest = path.join(guildPath, file.guildPath);
394	        await mkdir(path.dirname(dest), { recursive: true });
395	        await copyFile(file.sourcePath, dest);
396	        filesCopied.push(file);
397	      }
398	
399	      return {
400	        status: 'completed',
401	        yields: {
402	          guildName,
403	          guildPath,
404	          pluginsResolved,
405	          codexesAdded,
406	          filesCopied,
407	        },
408	      };
409	    } catch (err) {
410	      // Best-effort rollback: remove the guild dir if we got far enough
411	      // to create it. This means partial-state is not left behind for
412	      // teardown to clean up — every setup attempt is all-or-nothing.
413	      if (initialized) {
414	        try {
415	          await rm(guildPath, { recursive: true, force: true });
416	        } catch {
417	          // swallow — primary error is what we re-throw
418	        }
419	      }
420	      throw err;
421	    }
422	  },
423	};
424	
425	// ── Teardown engine ──────────────────────────────────────────────────
426	
427	export const guildTeardownEngine: EngineDesign = {
428	  id: 'lab.guild-teardown',
429	  async run(rawGivens, context: EngineRunContext): Promise<EngineRunResult> {
430	    const { guildName, guildPath } = validateGivens(rawGivens, 'lab.guild-teardown');
431	
432	    // Archive-safety check — same discipline as codex-teardown.
433	    if (context.upstream.archive === undefined || context.upstream.archive === null) {
434	      throw new Error(
435	        `[lab.guild-teardown] refusing to teardown guild "${guildName}": ` +
436	          `archive engine has not yielded for this rig. Teardown's upstream chain ` +
437	          `must include the archive engine. (When the archive engine is real, this ` +
438	          `check tightens — see click c-momaa5o9.)`,
439	      );
440	    }
441	
442	    // rm -rf — tolerant of "doesn't exist".
443	    await rm(guildPath, { recursive: true, force: true });
444	
445	    return {
446	      status: 'completed',
447	      yields: {
448	        removed: true,
449	        guildName,
450	        guildPath,
451	      },
452	    };
453	  },
454	};
455

