190	export async function waitForWritTerminal(opts: {
191	  testGuildPath: string;
192	  writId: string;
193	  pollIntervalMs: number;
194	  timeoutMs: number;
195	  designId: string;
196	}): Promise<TerminalSnapshot> {
197	  const startedAt = Date.now();
198	  while (true) {
199	    const elapsed = Date.now() - startedAt;
200	    if (elapsed > opts.timeoutMs) {
201	      throw new Error(
202	        `[${opts.designId}] timed out after ${opts.timeoutMs}ms waiting for writ ` +
203	          `${opts.writId} (test guild ${opts.testGuildPath}) to reach a terminal state.`,
204	      );
205	    }
206	
207	    const { stdout } = await exec('nsg', [
208	      '--guild-root',
209	      opts.testGuildPath,
210	      'writ-show',
211	      '--id',
212	      opts.writId,
213	      '--format',
214	      'json',
215	    ]);
216	
217	    let parsed: unknown;
218	    try {
219	      parsed = JSON.parse(stdout);
