1	/**
2	 * lab-trial-post tool — post a trial writ from a YAML manifest.
3	 *
4	 * CLI surface (via the framework's auto-grouping):
5	 *
6	 *     nsg lab trial-post <manifest>
7	 *     nsg lab trial-post --manifest <path> [--draft]
8	 *
9	 * Steps:
10	 *   1. Read and validate the manifest YAML (parse, schema, fixture
11	 *      DAG, probe id uniqueness).
12	 *   2. Translate to a writ-post shape + the trial config that lands
13	 *      under `ext.laboratory.config`.
14	 *   3. Post the writ via `clerk.post` (type: 'trial').
15	 *   4. Stamp the trial config via `clerk.setWritExt` under the
16	 *      'laboratory' plugin id.
17	 *   5. Unless `--draft` is set, transition the writ from 'new' to
18	 *      'open' so the rig fires immediately (parallel to the
19	 *      `commission-post` UX for mandates).
20	 *
21	 * The codex parameter follows the same auto-resolution rules
22	 * commission-post uses: when omitted, inherit from parentId; or if
23	 * the guild has exactly one registered codex, default to that;
24	 * otherwise the call fails with a clear error.
25	 */
26	
27	import { z } from 'zod';
28	import { guild } from '@shardworks/nexus-core';
29	import { tool } from '@shardworks/tools-apparatus';
30	import type { ClerkApi } from '@shardworks/clerk-apparatus';
31	import { manifestToWritShape, readManifestFile } from '../manifest.ts';
32	import { TRIAL_TYPE_NAME } from '../types.ts';
33	
34	/** Plugin id for the laboratory ext slot. */
35	const LABORATORY_PLUGIN_ID = 'laboratory';
36	
37	/**
38	 * Minimal structural subset of the codexes apparatus's API the
39	 * handler relies on for the auto-resolution shortcut. Declared
40	 * locally to keep `codexes` a soft (recommends) dependency — the
41	 * trial-post handler does not import the codexes package.
42	 */
43	interface CodexRegistry {
44	  list(): Promise<Array<{ name: string }>>;
45	}
46	
47	export default tool({
48	  name: 'lab-trial-post',
49	  description: 'Post a trial writ from a YAML manifest',
50	  instructions:
51	    'Reads a YAML manifest describing the trial (slug, fixtures, scenario, probes, archive), ' +
52	    'validates it (schema + fixture DAG + probe id uniqueness), posts a trial writ with the ' +
53	    'config attached at ext.laboratory.config, and (unless --draft is passed) transitions the ' +
54	    'writ from new to open so the rig fires. The manifest schema mirrors LaboratoryTrialConfig ' +
55	    'with optional title, description, parentId, and codex fields. ' +
56	    'Codex resolution follows commission-post conventions: omitted codex inherits from parentId ' +
57	    'when provided; otherwise defaults to the single registered codex when the guild has exactly ' +
58	    'one, fails with a clear error when the guild has multiple, and fails when none are registered.',
59	  params: {
60	    manifest: z.string().describe('Path to the YAML manifest file describing the trial.'),
61	    draft: z
62	      .boolean()
63	      .optional()
64	      .describe(
65	        'When true, leave the writ in new (draft) phase instead of transitioning to open. ' +
66	        'Draft writs are held out of the queue until explicitly published with writ-publish.',
67	      ),
68	  },
69	  permission: 'write',
70	  handler: async (params) => {
71	    const manifest = await readManifestFile(params.manifest);
72	    const { title, body, parentId, codex, trialConfig } = manifestToWritShape(manifest);
73	
74	    const clerk = guild().apparatus<ClerkApi>('clerk');
75	
76	    // Resolve parentId via clerk's id-resolver (accepts prefixes and
77	    // canonical ids).
78	    const resolvedParentId = parentId ? await clerk.resolveId(parentId) : undefined;
79	
