1	/**
2	 * Shared fixture module for Spider unit tests.
3	 *
4	 * Houses the canonical `buildFixture` integration harness and its
5	 * module-scope helper dependencies, originally co-located with the
6	 * monolithic `spider.test.ts`. The split into per-feature test files
7	 * relocates these helpers here so each split file imports only the
8	 * helpers it actually uses.
9	 *
10	 * The file name does not match the `*.test.ts` glob, so the test runner
11	 * never picks it up directly. Production source is imported directly
12	 * from the original packages — this module deliberately does NOT
13	 * re-export production symbols (no barrel pattern).
14	 */
15	
16	import assert from 'node:assert/strict';
17	
18	import { setGuild, generateId } from '@shardworks/nexus-core';
19	import type { Guild, GuildConfig, LoadedKit, LoadedApparatus, StartupContext, KitEntry } from '@shardworks/nexus-core';
20	
21	import { createStacksApparatus } from '@shardworks/stacks-apparatus';
22	import { MemoryBackend } from '@shardworks/stacks-apparatus/testing';
23	import type { StacksApi } from '@shardworks/stacks-apparatus';
24	
25	import { createClerk } from '@shardworks/clerk-apparatus';
26	import type { ClerkApi, WritDoc, WritTypeConfig } from '@shardworks/clerk-apparatus';
27	
28	import { createFabricator } from '@shardworks/fabricator-apparatus';
29	import type { FabricatorApi } from '@shardworks/fabricator-apparatus';
30	
31	import { freshStatusDoc } from '@shardworks/animator-apparatus';
32	import type { AnimatorApi, SummonRequest, AnimateHandle, SessionChunk, SessionResult, SessionDoc } from '@shardworks/animator-apparatus';
33	
34	import { createSpider } from './spider.ts';
35	import type { SpiderApi, RigDoc, EngineInstance, EngineAttempt, RigTemplate } from './types.ts';
36	
37	// ── Test bootstrap ────────────────────────────────────────────────────
38	
39	/**
40	 * Return the latest attempt row (tail of `attempts[]`) for the given engine,
41	 * or undefined if the engine has never been dispatched. Tests read
42	 * session id / yields / error / timestamps from this row (the scalar
43	 * engine-level fields no longer exist).
44	 */
45	export function latestAttempt(engine: EngineInstance): EngineAttempt | undefined {
46	  return engine.attempts && engine.attempts.length > 0 ? engine.attempts[engine.attempts.length - 1] : undefined;
47	}
48	
49	// Standard 5-engine template matching the original static pipeline behavior.
50	// Used as the default template in test fixtures.
51	export const STANDARD_TEMPLATE: RigTemplate = {
52	  engines: [
53	    { id: 'draft',     designId: 'draft',     givens: { writ: '${writ}' } },
54	    { id: 'implement', designId: 'implement', upstream: ['draft'],     givens: { writ: '${writ}', role: '${vars.role}' } },
55	    { id: 'review',    designId: 'review',    upstream: ['implement'], givens: { writ: '${writ}', role: 'reviewer', buildCommand: '${vars.buildCommand}', testCommand: '${vars.testCommand}' } },
56	    { id: 'revise',    designId: 'revise',    upstream: ['review'],    givens: { writ: '${writ}', role: '${vars.role}' } },
57	    { id: 'seal',      designId: 'seal',      upstream: ['revise'],    givens: {} },
58	  ],
59	  resolutionEngine: 'seal',
60	};
61	
62	export const FRAMEWORK_KIT_FIELDS = new Set(['requires', 'recommends']);
63	
64	export function buildKitEntries(kits: LoadedKit[], apparatuses: LoadedApparatus[]): KitEntry[] {
65	  const entries: KitEntry[] = [];
66	  for (const kit of kits) {
67	    for (const [type, value] of Object.entries(kit.kit)) {
68	      if (FRAMEWORK_KIT_FIELDS.has(type)) continue;
69	      entries.push({ pluginId: kit.id, packageName: kit.packageName, type, value });
70	    }
71	  }
72	  for (const app of apparatuses) {
73	    const bag = app.apparatus.supportKit;
74	    if (!bag || typeof bag !== 'object') continue;
75	    for (const [type, value] of Object.entries(bag)) {
76	      if (FRAMEWORK_KIT_FIELDS.has(type)) continue;
77	      entries.push({ pluginId: app.id, packageName: app.packageName, type, value });
78	    }
79	  }
80	  return entries;
81	}
82	
83	/**
84	 * Build a minimal StartupContext that captures and fires events.
85	 */
86	export function buildCtx(kitEntries: KitEntry[] = []): {
87	  ctx: StartupContext;
88	  fire: (event: string, ...args: unknown[]) => Promise<void>;
89	} {
90	  const handlers = new Map<string, Array<(...args: unknown[]) => void | Promise<void>>>();
91	  const ctx: StartupContext = {
92	    on(event, handler) {
93	      const list = handlers.get(event) ?? [];
94	      list.push(handler);
95	      handlers.set(event, list);
96	    },
97	    kits(type: string): KitEntry[] {
98	      return [...kitEntries.filter(e => e.type === type)];
99	    },
100	  };
101	  async function fire(event: string, ...args: unknown[]): Promise<void> {
102	    for (const h of handlers.get(event) ?? []) {
103	      await h(...args);
104	    }
105	  }
106	  return { ctx, fire };
107	}
108	
109	/**
110	 * Splice test-supplied custom engines into a copy of Spider's apparatus
111	 * supportKit. Matching is by engine id — if `customEngines` contains an
112	 * engine whose id matches one of Spider's built-in engines, that built-in is
113	 * replaced rather than registered alongside (which would violate the
114	 * Fabricator's kit-vs-kit uniqueness rule). Engines with new ids are
115	 * appended. Returns the same apparatus object unmodified when there are no
116	 * custom engines.
117	 */
118	export function mergeCustomEnginesIntoSpider(
119	  spiderApparatus: LoadedApparatus['apparatus'],
120	  customEngines: Record<string, unknown> | undefined,
121	): LoadedApparatus['apparatus'] {
122	  if (!customEngines || Object.keys(customEngines).length === 0) {
123	    return spiderApparatus;
124	  }
125	
126	  const spiderSupportKit = (spiderApparatus as { supportKit?: Record<string, unknown> }).supportKit ?? {};
127	  const spiderEngines = (spiderSupportKit.engines ?? {}) as Record<string, unknown>;
128	
129	  // Collect the ids of custom engines so we can filter Spider's built-ins.
130	  const customIds = new Set<string>();
131	  for (const val of Object.values(customEngines)) {
132	    const id = (val as { id?: unknown }).id;
133	    if (typeof id === 'string') customIds.add(id);
134	  }
135	
136	  // Rebuild Spider's engine record, dropping any built-in whose id collides
137	  // with a custom engine's id. The surviving built-ins are keyed by their
138	  // original record key (which may or may not match the engine id).
139	  const survivingBuiltins: Record<string, unknown> = {};
140	  for (const [key, value] of Object.entries(spiderEngines)) {
141	    const id = (value as { id?: unknown }).id;
142	    if (typeof id !== 'string' || !customIds.has(id)) {
143	      survivingBuiltins[key] = value;
144	    }
145	  }
146	
147	  return {
148	    ...spiderApparatus,
149	    supportKit: {
150	      ...spiderSupportKit,
151	      engines: { ...survivingBuiltins, ...customEngines },
152	    },
153	  } as LoadedApparatus['apparatus'];
154	}
155	
156	/**
157	 * Full integration fixture: starts Stacks (memory), Clerk, Fabricator,
158	 * and Spider. Returns handles to each API plus mock animator controls.
159	 */
160	export function buildFixture(
161	  guildConfig: Partial<GuildConfig> = {},
162	  initialSessionOutcome: { status: 'completed' | 'failed'; error?: string; output?: string } = { status: 'completed' },
163	  extra: {
164	    kits?: LoadedKit[];
165	    apparatuses?: LoadedApparatus[];
166	    customEngines?: Record<string, unknown>;
167	    /**
168	     * Additional writ-type configs to register with the Clerk after its
169	     * `start()` returns. The legacy `clerk.writTypes` guild-config channel
170	     * and kit-channel scan have both been retired; tests that need
171	     * non-mandate writ types register them here. Each config is a full
172	     * `WritTypeConfig`; common test types (`triage`, `audit`) clone
173	     * mandate's six-state machine.
174	     */
175	    extraWritTypes?: WritTypeConfig[];
176	  } = {},
177	): {
178	  stacks: StacksApi;
179	  clerk: ClerkApi;
180	  realClerk: ClerkApi;
181	  fabricator: FabricatorApi;
182	  spider: SpiderApi;
183	  memBackend: InstanceType<typeof MemoryBackend>;
184	  fire: (event: string, ...args: unknown[]) => Promise<void>;
185	  spiderFire: (event: string, ...args: unknown[]) => Promise<void>;
186	  summonCalls: SummonRequest[];
187	  cancelCalls: Array<{ sessionId: string; options?: { reason?: string } }>;
188	  setSessionOutcome: (outcome: { status: 'completed' | 'failed'; error?: string; output?: string }) => void;
189	} {
190	  const memBackend = new MemoryBackend();
191	  const stacksPlugin = createStacksApparatus(memBackend);
192	  const clerkPlugin = createClerk();
193	  const fabricatorPlugin = createFabricator();
194	  const spiderPlugin = createSpider();
195	
196	  if (!('apparatus' in stacksPlugin)) throw new Error('stacks must be apparatus');
197	  if (!('apparatus' in clerkPlugin)) throw new Error('clerk must be apparatus');
198	  if (!('apparatus' in fabricatorPlugin)) throw new Error('fabricator must be apparatus');
199	  if (!('apparatus' in spiderPlugin)) throw new Error('spider must be apparatus');
200	
201	  const stacksApparatus = stacksPlugin.apparatus;
202	  const clerkApparatus = clerkPlugin.apparatus;
203	  const fabricatorApparatus = fabricatorPlugin.apparatus;
204	  const spiderApparatus = spiderPlugin.apparatus;
205	
206	  const apparatusMap = new Map<string, unknown>();
207	
208	  const mergedSpider = {
209	    rigTemplates: { default: STANDARD_TEMPLATE } as Record<string, RigTemplate>,
210	    variables: { role: 'artificer' } as Record<string, unknown>,
211	    ...(guildConfig.spider ?? {}),
212	  };
213	
214	  // Note: the fixture no longer auto-injects { mandate: 'default' } into
215	  // rigTemplateMappings. Spider's registry applies a narrow mandate-
216	  // builtin fallback inside `lookup()`/`listTemplateMappings()` — when
217	  // no config or kit mapping claims the `mandate` writ type, mandate
218	  // writs resolve to a `default` / `spider.default` template if one is
219	  // registered. Tests that post mandate writs against the
220	  // STANDARD_TEMPLATE (registered as config-level `default`) get the
221	  // same dispatch behaviour without test-fixture machinery. Tests that
222	  // exercise a non-default mapping declare their own config override
223	  // explicitly.
224	
225	  const fakeGuildConfig: GuildConfig = {
226	    name: 'test-guild',
227	    nexus: '0.0.0',
228	    plugins: [],
229	    ...guildConfig,
230	    spider: mergedSpider,
231	  };
232	
233	  const fakeGuild: Guild = {
234	    home: '/tmp/test-guild',
235	    apparatus<T>(name: string): T {
236	      const api = apparatusMap.get(name);
237	      if (!api) throw new Error(`Apparatus "${name}" not found`);
238	      return api as T;
239	    },
240	
241	    tryApparatus<T>(name: string): T | null {
242	      try { return this.apparatus<T>(name); } catch { return null; }
243	    },
244	    config<T>(_pluginId: string): T { return {} as T; },
245	    writeConfig() {},
246	    guildConfig() { return fakeGuildConfig; },
247	    kits(): LoadedKit[] { return extra.kits ?? []; },
248	    apparatuses(): LoadedApparatus[] { return extra.apparatuses ?? []; },
249	    startupWarnings() { return []; },
250	    failedPlugins() { return []; },
251	  };
252	
253	  setGuild(fakeGuild);
254	
255	  // Build Spider's LoadedApparatus, optionally splicing test-supplied custom
256	  // engines into Spider's supportKit.engines by engine id. This preserves the
257	  // decades-old test pattern of "stub out a Spider engine" while keeping the
258	  // Fabricator's kit-vs-kit uniqueness invariant intact — a stub and Spider's
259	  // real engine with the same id are never both registered. New engine ids
260	  // (with no matching Spider built-in) are simply appended.
261	  const spiderAsLoaded: LoadedApparatus = {
262	    packageName: '@shardworks/spider-apparatus',
263	    id: 'spider',
264	    version: '0.0.0',
265	    apparatus: mergeCustomEnginesIntoSpider(spiderApparatus, extra.customEngines),
266	  };
267	
268	  // Mirror production wiring: Arbor's `buildKitEntries` walks every loaded
269	  // apparatus's `supportKit` including Clerk's. Include Clerk's own
270	  // apparatus in the kit-entry pool so its self-contributed link kinds
271	  // (notably `depends-on`) flow through the same path they take in
272	  // production. Without this, the Clerk would not see its own contribution
273	  // through `ctx.kits('linkKinds')` and the dependency-link kind would be
274	  // missing from the test registry.
275	  const clerkAsLoaded: LoadedApparatus = {
276	    packageName: '@shardworks/clerk-apparatus',
277	    id: 'clerk',
278	    version: '0.0.0',
279	    apparatus: clerkApparatus,
280	  };
281	
282	  const fabricatorKitEntries = buildKitEntries(
283	    extra.kits ?? [],
284	    [clerkAsLoaded, spiderAsLoaded, ...(extra.apparatuses ?? [])],
285	  );
286	
287	  const spiderKitEntries = buildKitEntries(
288	    extra.kits ?? [],
289	    [clerkAsLoaded, spiderAsLoaded, ...(extra.apparatuses ?? [])],
290	  );
291	
292	  // Start stacks with memory backend
293	  const noopCtx = { on: () => {}, kits: () => [] as KitEntry[] };
294	  stacksApparatus.start(noopCtx);
295	  const stacks = stacksApparatus.provides as StacksApi;
296	  apparatusMap.set('stacks', stacks);
297	
298	  // Manually ensure all books the Spider and Clerk need
299	  memBackend.ensureBook({ ownerId: 'clerk', book: 'writs' }, {
300	    indexes: ['phase', 'type', 'createdAt', 'parentId', ['phase', 'type'], ['phase', 'createdAt'], ['parentId', 'phase']],
301	  });
302	  memBackend.ensureBook({ ownerId: 'spider', book: 'rigs' }, {
303	    indexes: ['status', 'writId', ['status', 'writId'], 'createdAt'],
304	  });
305	  memBackend.ensureBook({ ownerId: 'spider', book: 'input-requests' }, {
306	    indexes: ['status', 'rigId', 'engineId', 'createdAt', ['rigId', 'engineId', 'status']],
307	  });
308	  memBackend.ensureBook({ ownerId: 'animator', book: 'sessions' }, {
309	    indexes: ['startedAt', 'status'],
310	  });
311	
312	  // Mock animator — captures summon() calls and writes session docs to Stacks.
313	  // The session record is written eagerly (synchronous put, fire-and-forget)
314	  // so the Spider's collect step finds it on the next crawl() call. Engines
315	  // no longer await handle.result — they return immediately with handle.sessionId.
316	  let currentSessionOutcome = initialSessionOutcome;
317	  const summonCalls: SummonRequest[] = [];
318	  const cancelCalls: Array<{ sessionId: string; options?: { reason?: string } }> = [];
319	  const mockAnimatorApi: AnimatorApi = {
320	    summon(request: SummonRequest): AnimateHandle {
321	      summonCalls.push(request);
322	      const sessionId = generateId('ses', 4);
323	      const startedAt = new Date().toISOString();
324	      const outcome = currentSessionOutcome;
325	
326	      const sessBook = stacks.book<SessionDoc>('animator', 'sessions');
327	      const endedAt = new Date().toISOString();
328	      const doc: SessionDoc = {
329	        id: sessionId,
330	        status: outcome.status,
331	        startedAt,
332	        endedAt,
333	        durationMs: 0,
334	        provider: 'mock',
335	        exitCode: outcome.status === 'completed' ? 0 : 1,
336	        ...(outcome.error ? { error: outcome.error } : {}),
337	        ...(outcome.output !== undefined ? { output: outcome.output } : {}),
338	        metadata: request.metadata,
339	      };
340	      // Write eagerly — fire and forget. The in-memory backend is sync.
341	      void sessBook.put(doc);
342	
343	      const result = Promise.resolve({
344	        id: sessionId,
345	        status: outcome.status,
346	        startedAt,
347	        endedAt,
348	        durationMs: 0,
349	        provider: 'mock',
350	        exitCode: outcome.status === 'completed' ? 0 : 1,
351	        ...(outcome.error ? { error: outcome.error } : {}),
352	        ...(outcome.output !== undefined ? { output: outcome.output } : {}),
353	        metadata: request.metadata,
354	      } as SessionResult);
355	
356	      async function* emptyChunks(): AsyncIterable<SessionChunk> {}
357	      return { sessionId, chunks: emptyChunks(), result };
358	    },
359	    animate(): AnimateHandle {
360	      throw new Error('animate() not used in Spider tests');
361	    },
362	    subscribeToSession(): AsyncIterable<SessionChunk> | null {
363	      return null;
364	    },
365	    async cancel(sessionId: string, options?: { reason?: string }): Promise<SessionDoc> {
366	      cancelCalls.push({ sessionId, options });
367	      const sessBook = stacks.book<SessionDoc>('animator', 'sessions');
368	      const session = await sessBook.get(sessionId);
369	      if (session) {
370	        const now = new Date().toISOString();
371	        await sessBook.patch(sessionId, {
372	          status: 'cancelled',
373	          endedAt: now,
374	          ...(options?.reason ? { error: options.reason } : {}),
375	        });
376	        return { ...session, status: 'cancelled', endedAt: now };
377	      }
378	      return { id: sessionId, status: 'cancelled', startedAt: '', endedAt: '', durationMs: 0, provider: 'mock', exitCode: 1 } as SessionDoc;
379	    },
380	    async getSessionCosts() { return new Map(); },
381	    async getStatus() { return freshStatusDoc(); },
382	  };
383	  apparatusMap.set('animator', mockAnimatorApi);
384	
385	  // Start clerk. Clerk consumes `linkKinds` kit entries, so pass the full
386	  // kit-entry snapshot through its ctx — this is how `depends-on` (now
387	  // contributed by Clerk's own supportKit, mirrored here via `clerkAsLoaded`
388	  // above) gets registered in the kind registry and becomes acceptable to
389	  // `clerk.link(_, _, _, 'depends-on')`. Production wiring (Arbor's
390	  // `buildKitEntries`) walks every loaded apparatus's `supportKit` including
391	  // Clerk's; the fixture mimics that exactly.
392	  const { ctx: clerkCtx } = buildCtx(spiderKitEntries);
393	  clerkApparatus.start(clerkCtx);
394	  const realClerk = clerkApparatus.provides as ClerkApi;
395	
396	  // Register any extra writ types this test needs. The harness never fires
397	  // `phase:started`, so the Clerk's registration window stays open.
398	  for (const config of extra.extraWritTypes ?? []) {
399	    realClerk.registerWritType(config);
400	  }
401	
402	  // Fixture wrapper: most legacy spider tests post a writ and expect it to
403	  // be in `open` (dispatchable) immediately — that was the
404	  // pre-registry-refactor auto-publish semantics. The post-refactor
405	  // ClerkApi.post() lands the writ in its declared initial state (`new`).
406	  // The wrapper preserves the fixture's prior behaviour by auto-publishing
407	  // *any* writ that lands in the `new` state — every type used by spider
408	  // tests (mandate, triage, audit, custom-type, orphan-type, etc.) declares
409	  // `new → open` as a legal transition, so the auto-publish maps cleanly
410	  // onto the legacy `draft: false` semantics. This is a test-fixture
411	  // concession, not an API change. Tests that need a writ to stay in `new`
412	  // can call `realClerk.post(...)` directly via
413	  // `(fix as { realClerk: ClerkApi }).realClerk`.
414	  const clerk: ClerkApi = {
415	    ...realClerk,
416	    async post(request) {
417	      const writ = await realClerk.post(request);
418	      if (writ.phase === 'new') {
419	        return realClerk.transition(writ.id, 'open');
420	      }
421	      return writ;
422	    },
423	  };
424	  apparatusMap.set('clerk', clerk);
425	
426	  // Start fabricator with kit entries from Spider's engines
427	  const { ctx: fabricatorCtx, fire } = buildCtx(fabricatorKitEntries);
428	  fabricatorApparatus.start(fabricatorCtx);
429	  const fabricator = fabricatorApparatus.provides as FabricatorApi;
430	  apparatusMap.set('fabricator', fabricator);
431	
432	  // Start spider with kit entries from Spider's supportKit
433	  const { ctx: spiderCtx, fire: spiderFire } = buildCtx(spiderKitEntries);
434	  spiderApparatus.start(spiderCtx);
435	  const spider = spiderApparatus.provides as SpiderApi;
436	  apparatusMap.set('spider', spider);
437	
438	  return {
439	    stacks, clerk, realClerk, fabricator, spider, memBackend, fire, spiderFire,
440	    summonCalls,
441	    cancelCalls,
442	    setSessionOutcome(outcome: { status: 'completed' | 'failed'; error?: string; output?: string }) {
443	      currentSessionOutcome = outcome;
444	    },
445	  };
446	}
447	
448	/** Get the rigs book. */
449	export function rigsBook(stacks: StacksApi) {
450	  return stacks.book<RigDoc>('spider', 'rigs');
451	}
452	
453	/**
454	 * Build a `WritTypeConfig` that clones mandate's six-state machine under a
455	 * different name. Used by tests that previously declared throwaway writ
456	 * types via the legacy `clerk.writTypes` guild-config channel.
457	 */
458	export function mandateLikeWritType(name: string): WritTypeConfig {
459	  return {
460	    name,
461	    states: [
462	      { name: 'new', classification: 'initial', allowedTransitions: ['open', 'cancelled'] },
463	      { name: 'open', classification: 'active', allowedTransitions: ['stuck', 'completed', 'failed', 'cancelled'] },
464	      { name: 'stuck', classification: 'active', attrs: ['stuck'], allowedTransitions: ['open', 'failed', 'cancelled'] },
465	      { name: 'completed', classification: 'terminal', attrs: ['success'], allowedTransitions: [] },
466	      { name: 'failed', classification: 'terminal', attrs: ['failure'], allowedTransitions: [] },
467	      { name: 'cancelled', classification: 'terminal', attrs: ['cancelled'], allowedTransitions: [] },
468	    ],
469	  };
470	}
471	
472	/**
473	 * Post a mandate writ. The fixture's clerk wrapper auto-publishes mandate
474	 * writs to `open`, so this helper is now a thin convenience that just sets
475	 * a default title and body. (The auto-publish lives in the wrapper, not
476	 * this helper, so callers that go through `fix.clerk.post(...)` directly
477	 * get the same `open`-on-arrival behaviour.)
478	 */
479	export async function postWrit(clerk: ClerkApi, title = 'Test writ', codex?: string): Promise<WritDoc> {
480	  return clerk.post({ title, body: 'Test body', codex });
481	}
482	
483	/**
484	 * Assert that a rig's terminalAt field is a valid ISO timestamp. Used by
485	 * rig terminal-transition tests to pin the invariant that any rig reaching
486	 * a terminal status also records the terminal-event timestamp.
487	 */
488	export function assertTerminalAt(rig: { terminalAt?: string } | null | undefined, msg = 'rig.terminalAt should be a valid ISO timestamp'): void {
489	  assert.ok(rig, 'rig should be defined for terminalAt check');
490	  assert.ok(
491	    typeof rig!.terminalAt === 'string' && /^\d{4}-\d{2}-\d{2}T/.test(rig!.terminalAt),
492	    `${msg} (got: ${JSON.stringify(rig!.terminalAt)})`,
493	  );
494	}
